def parse_user_input(prompt: str) -> list:
    """Parse comma-separated user input into a list."""
    raw = input(prompt).strip()
    if not raw:
        return []
    return [item.strip() for item in raw.split(",")]


def display_templates():
    """Display available script templates."""
    print("\n" + "=" * 60)
    print("Available Script Templates:")
    print("=" * 60)
    for name, info in SCRIPT_TEMPLATES.items():
        print(f"\n  [{name}]")
        print(f"    Description: {info['description']}")
        print(f"    Usage: {info['usage']}")
    print("\n" + "=" * 60)


